SELECT COUNT(1)
FROM growth_points_log
WHERE user_id = #{userId}

SELECT COUNT(1)
FROM growth_points_log
WHERE user_id = #{userId}
  AND action = #{action}
  AND type = #{type}
  AND biz_id = #{bizId}

SELECT level FROM level_config
WHERE enabled = TRUE AND min_growth <= #{growthValue}
ORDER BY min_growth DESC, level DESC LIMIT 1
